def prove_pm5_74(sys: System) -> Proof:
    """Distribution of implication over biconditional.  Theorem *5.74 of
    [WhiteheadRussell] p. 126.  (Contributed by NM, 1-Aug-1994.)  (Proof
    shortened by Wolf Lammen, 11-Apr-2013.)
    """
    lb = ProofBuilder(sys, "pm5.74")
    s1 = lb.ref("s1", "( ( ψ ↔ χ ) → ( ψ → χ ) )", ref="biimp", note="biimp")
    s2 = lb.ref("s2", "( ( φ → ( ψ ↔ χ ) ) → ( ( φ → ψ ) → ( φ → χ ) ) )", s1, ref="imim3i", note="imim3i")
    s3 = lb.ref("s3", "( ( ψ ↔ χ ) → ( χ → ψ ) )", ref="biimpr", note="biimpr")
    s4 = lb.ref("s4", "( ( φ → ( ψ ↔ χ ) ) → ( ( φ → χ ) → ( φ → ψ ) ) )", s3, ref="imim3i", note="imim3i")
    s5 = lb.ref("s5", "( ( φ → ( ψ ↔ χ ) ) → ( ( φ → ψ ) ↔ ( φ → χ ) ) )", s2, s4, ref="impbid", note="impbid")
    s6 = lb.ref("s6", "( ( ( φ → ψ ) ↔ ( φ → χ ) ) → ( ( φ → ψ ) → ( φ → χ ) ) )", ref="biimp", note="biimp")
    s7 = lb.ref("s7", "( ( ( φ → ψ ) ↔ ( φ → χ ) ) → ( φ → ( ψ → χ ) ) )", s6, ref="pm2.86d", note="pm2.86d")
    s8 = lb.ref("s8", "( ( ( φ → ψ ) ↔ ( φ → χ ) ) → ( ( φ → χ ) → ( φ → ψ ) ) )", ref="biimpr", note="biimpr")
    s9 = lb.ref("s9", "( ( ( φ → ψ ) ↔ ( φ → χ ) ) → ( φ → ( χ → ψ ) ) )", s8, ref="pm2.86d", note="pm2.86d")
    s10 = lb.ref("s10", "( ( ( φ → ψ ) ↔ ( φ → χ ) ) → ( φ → ( ψ ↔ χ ) ) )", s7, s9, ref="impbidd", note="impbidd")
    res = lb.ref("res", "( ( φ → ( ψ ↔ χ ) ) ↔ ( ( φ → ψ ) ↔ ( φ → χ ) ) )", s5, s10, ref="impbii", note="impbii")
    return lb.build(res)

