    s3 = lb.ref("s3", "( φ → ( ψ → χ ) )", h1, ref="biimpd", note="biimpd")
    s4 = lb.ref("s4", "( φ → ( ( χ → θ ) → ( ψ → θ ) ) )", s3, ref="imim1d", note="imim1d")
    res = lb.ref("res", "( φ → ( ( ψ → θ ) ↔ ( χ → θ ) ) )", s2, s4, ref="impbid", note="impbid")
