    s2 = lb.ref("s2", "( φ → ( ( χ ↔ θ ) ↔ ( χ ↔ τ ) ) )", h2, ref="bibi2d", note="bibi2d")
    res = lb.ref("res", "( φ → ( ( ψ ↔ θ ) ↔ ( χ ↔ τ ) ) )", s1, s2, ref="bitrd", note="bitrd")
