def prove_imbi12(sys: System) -> Proof:
    """Closed form of ~ imbi12i .  Was automatically derived from its "Virtual
    Deduction" version and the Metamath program "MM-PA> MINIMIZE__WITH *"
    command.  (Contributed by Alan Sare, 18-Mar-2012.)
    """
    lb = ProofBuilder(sys, "imbi12")
    s1 = lb.ref("s1", "( ¬ ( ( φ ↔ ψ ) → ¬ ( χ ↔ θ ) ) → ( φ ↔ ψ ) )", ref="simplim", note="simplim")
    s2 = lb.ref("s2", "( ¬ ( ( φ ↔ ψ ) → ¬ ( χ ↔ θ ) ) → ( χ ↔ θ ) )", ref="simprim", note="simprim")
    s3 = lb.ref("s3", "( ¬ ( ( φ ↔ ψ ) → ¬ ( χ ↔ θ ) ) → ( ( φ → χ ) ↔ ( ψ → θ ) ) )", s1, s2, ref="imbi12d", note="imbi12d")
    res = lb.ref("res", "( ( φ ↔ ψ ) → ( ( χ ↔ θ ) → ( ( φ → χ ) ↔ ( ψ → θ ) ) ) )", s3, ref="expi", note="expi")
    return lb.build(res)

